INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('namnso', 'Namnso Ukpanah', 'Lagos, Nigeria', 'Editorial', '24.1k', 'https://images.unsplash.com/photo-1749058387715-1efad0eadc8c?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', 'Editorial and documentary photographer based in Lagos, drawn to unhurried portraits of everyday life across West Africa.', 'https://images.unsplash.com/photo-1749058387715-1efad0eadc8c?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', TRUE, ARRAY['Sony A7 IV','35mm f/1.4','85mm f/1.8']);
INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('jessica-felicio', 'Jessica Felicio', 'Lisbon, Portugal', 'Lifestyle', '31.6k', 'https://images.unsplash.com/photo-1527201987695-67c06571957e?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', 'Lifestyle photographer capturing joy, movement and light. Believer in imagery that feels lived-in, not staged.', 'https://images.unsplash.com/photo-1527201987695-67c06571957e?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', TRUE, ARRAY['Sony A7 IV','50mm f/1.8']);
INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('prince-akachi', 'Prince Akachi', 'Lagos, Nigeria', 'Culture', '18.9k', 'https://images.unsplash.com/photo-1532076904124-d4e8fe7fbbec?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', 'Documenting culture, tradition and colour across Nigeria. Every frame is a small act of preservation.', 'https://images.unsplash.com/photo-1532076904124-d4e8fe7fbbec?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', TRUE, ARRAY['Leica Q2','28mm f/1.7']);
INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('godfred-kwakye', 'Godfred Kwakye', 'Accra, Ghana', 'Portrait', '12.4k', 'https://images.unsplash.com/photo-1713845784497-fe3d7ed176d8?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', 'Portrait photographer from Accra with a love for texture, gold light and quiet confidence.', 'https://images.unsplash.com/photo-1713845784497-fe3d7ed176d8?crop=entropy&cs=tinysrgb&fit=crop&fm=jpg&q=82&w=1080', TRUE, ARRAY['Canon EOS R5','85mm f/1.4']);
INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('patrick-watson-quine', 'Patrick Watson Quine', 'Montreal, Canada', 'Landscape', '8.9k', 'https://res.cloudinary.com/odu5iecy/image/upload/v1784203446/ns-captures/AM%20Downtown%20Closeup%20C-1.jpg', 'Landscape and cityscape photographer based in Canada, exploring the intersections of nature, architecture, and urban light.', 'https://res.cloudinary.com/odu5iecy/image/upload/v1784203446/ns-captures/AM%20Downtown%20Closeup%20C-1.jpg', TRUE, ARRAY['Leica M11','35mm f/1.4','90mm f/2.8 Macro']);
INSERT INTO public.photographers (id, name, location, specialty, followers, avatar, bio, cover, verified, gear) VALUES ('lexmond-dennis', 'Lexmond Dennis', 'Amsterdam, Netherlands', 'Landscape', '14.8k', 'https://res.cloudinary.com/odu5iecy/image/upload/v1784205071/ns-captures-lexmond/lexmond_photo_2.jpg', 'Landscape and architectural photographer capturing the quiet beauty, historic canals, and dramatic skies of the Netherlands and Europe.', 'https://res.cloudinary.com/odu5iecy/image/upload/v1784205071/ns-captures-lexmond/lexmond_photo_2.jpg', TRUE, ARRAY['Sony A7R V','FE 24-70mm f/2.8 GM II','FE 70-200mm f/2.8 GM OSS II']);
